url = lg.pp_url()[0].split('QCM')[0] + "RPT/bRPT0303.aspx"


def get_viewdata(url):
    """

    :param url: 获取viewstate网页的response
    :return: _viewstate
    """
    headers = {
        'accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,image/apng,*/*;q=0.8,application/signed-exchange;v=b3;q=0.7',
        'accept-language': 'zh-TW,zh;q=0.9,en-US;q=0.8,en;q=0.7',
        'cache-control': 'no-cache',
        'content-type': 'application/x-www-form-urlencoded',
        'origin': 'https://ksmes2.compal.com:9443',
        'pragma': 'no-cache',
        'priority': 'u=0, i',
        'referer': url,
        'sec-ch-ua': '"Not;A=Brand";v="99", "Google Chrome";v="139", "Chromium";v="139"',
        'sec-ch-ua-mobile': '?0',
        'sec-ch-ua-platform': '"Windows"',
        'sec-fetch-dest': 'iframe',
        'sec-fetch-mode': 'navigate',
        'sec-fetch-site': 'same-origin',
        'sec-fetch-user': '?1',
        'upgrade-insecure-requests': '1',
        'user-agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/139.0.0.0 Safari/537.36',
    }
    # 获取viewstate值
    resp = requests.get(url, headers=headers)
    resp.encoding = 'utf-8'
    obj = re.compile(
        r'id="__VIEWSTATE" value="(?P<_VIEWSTATE>.*?)" />',
        re.S)
    _VIEWSTATE = obj.search(resp.text).group("_VIEWSTATE")
    return _VIEWSTATE


